{"content":"// ============================================================
// NEON CHECKERS VR — Holographic Draughts Game
// Built with IWSDK 0.4.x — playable in VR and browser
// ============================================================

import {
  World, createSystem, PanelUI, PanelDocument, UIKitDocument, UIKit,
  BoxGeometry, MeshStandardMaterial, MeshBasicMaterial, Mesh,
  Color, Group, PointLight, DirectionalLight, AmbientLight, FogExp2,
  LineSegments, BufferGeometry, Float32BufferAttribute, LineBasicMaterial,
  SphereGeometry, CylinderGeometry, EdgesGeometry, Object3D,
  Follower, ScreenSpace, InputComponent,
  PlaneGeometry, RingGeometry, TorusGeometry, DoubleSide,
  Vector3, Raycaster, Vector2,
} from '@iwsdk/core';

// Runtime input interface
interface RuntimeInput {
  keyboard?: {
    getKeyDown(key: string): boolean;
    getKeyPressed(key: string): boolean;
  };
  gamepads: Record<'left'|'right', {
    getButtonDown(id: string): boolean;
    getButtonValue(id: string): number;
    getAxesValues(id: string): { x: number; y: number } | undefined;
  } | undefined>;
}

// ============================================================
// TYPES
// ============================================================
type Screen = 'title'|'modeselect'|'difficulty'|'playing'|'paused'|'gameover'|
  'leaderboard'|'achievements'|'stats'|'settings'|'help'|'skins'|'countdown';
type Mode = 'solo'|'vsai'|'timed'|'blitz'|'daily'|'marathon'|'zen'|'practice';
type PieceColor = 'red'|'black';
type Cell = { piece: PieceColor|null; king: boolean };
type Pos = { r: number; c: number };
type Move = { from: Pos; to: Pos; captures: Pos[]; };

const BOARD_SIZE = 8;
const CELL_SIZE = 0.12;
const BOARD_OFFSET = -(BOARD_SIZE * CELL_SIZE) / 2 + CELL_SIZE / 2;
const PIECE_RADIUS = 0.04;
const PIECE_HEIGHT = 0.015;
const BOARD_Y = 0.85;

// ============================================================
// THEMES
// ============================================================
interface Theme { name: string; accent: string; bg: string; fog: string; light: string; dark: string; gridC: string; }
const THEMES: Theme[] = [
  { name:'Neon Holodeck', accent:'#00ffff', bg:'#000a0f', fog:'#000a0f', light:'#1a2a35', dark:'#0a1520', gridC:'#004455' },
  { name:'Crimson Grid', accent:'#ff3366', bg:'#0f0005', fog:'#0f0005', light:'#2a1520', dark:'#1a0a10', gridC:'#440022' },
  { name:'Toxic Neon', accent:'#33ff33', bg:'#000f00', fog:'#000f00', light:'#1a2a1a', dark:'#0a150a', gridC:'#004400' },
  { name:'Ultra Violet', accent:'#aa55ff', bg:'#05000f', fog:'#05000f', light:'#201a2a', dark:'#100a1a', gridC:'#220044' },
  { name:'Solar Blaze', accent:'#ff8800', bg:'#0f0500', fog:'#0f0500', light:'#2a1a0a', dark:'#1a0a05', gridC:'#442200' },
];

// ============================================================
// SKINS
// ============================================================
interface Skin { name: string; redBody: string; redEdge: string; blackBody: string; blackEdge: string; unlock: string; req: (s: Save) => boolean; }
const SKINS: Skin[] = [
  { name:'Classic Neon', redBody:'#ff2244', redEdge:'#ff5566', blackBody:'#111111', blackEdge:'#00ffff', unlock:'Default', req:()=>true },
  { name:'Solar', redBody:'#ff6600', redEdge:'#ff8833', blackBody:'#0a1a30', blackEdge:'#3388ff', unlock:'Win 5 games', req:s=>s.totalWins>=5 },
  { name:'Toxic', redBody:'#00cc44', redEdge:'#33ff66', blackBody:'#330033', blackEdge:'#cc33ff', unlock:'Capture 50 pieces', req:s=>s.totalCaptures>=50 },
  { name:'Frost', redBody:'#2266cc', redEdge:'#55aaff', blackBody:'#220a0a', blackEdge:'#ff4444', unlock:'Win vs Hard AI', req:s=>s.hardWins>=1 },
  { name:'Gold', redBody:'#cc8800', redEdge:'#ffcc00', blackBody:'#1a1a1a', blackEdge:'#cccccc', unlock:'Get 5 kings', req:s=>(s.totalKings||0)>=5 },
  { name:'Void', redBody:'#880088', redEdge:'#cc44cc', blackBody:'#002211', blackEdge:'#00ffaa', unlock:'Play 20 games', req:s=>s.totalGames>=20 },
];

// ============================================================
// ACHIEVEMENTS
// ============================================================
interface Ach { id: string; name: string; desc: string; chk: (s: Save) => boolean; }
const ACHS: Ach[] = [
  { id:'first_game', name:'First Move', desc:'Complete your first game', chk:s=>s.totalGames>=1 },
  { id:'first_win', name:'Victor', desc:'Win your first game', chk:s=>s.totalWins>=1 },
  { id:'ten_games', name:'Regular', desc:'Play 10 games', chk:s=>s.totalGames>=10 },
  { id:'ten_wins', name:'Veteran', desc:'Win 10 games', chk:s=>s.totalWins>=10 },
  { id:'capture_10', name:'Hunter', desc:'Capture 10 pieces total', chk:s=>s.totalCaptures>=10 },
  { id:'capture_50', name:'Predator', desc:'Capture 50 pieces total', chk:s=>s.totalCaptures>=50 },
  { id:'multi_jump', name:'Chain Reaction', desc:'Make a triple jump', chk:s=>s.maxChainJump>=3 },
  { id:'quad_jump', name:'Unstoppable', desc:'Make a quadruple jump', chk:s=>s.maxChainJump>=4 },
  { id:'king_me', name:'Crowned', desc:'Get your first king', chk:s=>(s.totalKings||0)>=1 },
  { id:'five_kings', name:'Royal Court', desc:'Crown 5 kings total', chk:s=>(s.totalKings||0)>=5 },
  { id:'flawless', name:'Flawless', desc:'Win without losing a piece', chk:s=>s.flawlessWins>=1 },
  { id:'beat_easy', name:'Apprentice', desc:'Beat Easy AI', chk:s=>s.easyWins>=1 },
  { id:'beat_med', name:'Tactician', desc:'Beat Medium AI', chk:s=>s.medWins>=1 },
  { id:'beat_hard', name:'Grandmaster', desc:'Beat Hard AI', chk:s=>s.hardWins>=1 },
  { id:'speed_win', name:'Lightning', desc:'Win in under 2 minutes', chk:s=>s.fastestWin<120 },
  { id:'comeback', name:'Comeback Kid', desc:'Win when down 3+ pieces', chk:s=>s.comebackWins>=1 },
  { id:'sweep', name:'Clean Sweep', desc:'Capture all 12 opponent pieces', chk:s=>s.cleanSweeps>=1 },
  { id:'all_modes', name:'Explorer', desc:'Play all game modes', chk:s=>(s.modesPlayed?.size||0)>=6 },
  { id:'streak_3', name:'Hot Streak', desc:'Win 3 games in a row', chk:s=>s.bestStreak>=3 },
  { id:'streak_5', name:'On Fire', desc:'Win 5 games in a row', chk:s=>s.bestStreak>=5 },
  { id:'timed_win', name:'Time Lord', desc:'Win a timed game', chk:s=>s.timedWins>=1 },
  { id:'king_captures', name:'Royal Executioner', desc:'Capture 10 pieces with kings', chk:s=>(s.kingCaptures||0)>=10 },
  { id:'no_kings_win', name:'Peasant Power', desc:'Win without making any kings', chk:s=>s.noKingWins>=1 },
  { id:'fifty_wins', name:'Legend', desc:'Win 50 games', chk:s=>s.totalWins>=50 },
  { id:'perfect_game', name:'Perfect Game', desc:'Win capturing all 12 & losing none', chk:s=>s.perfectGames>=1 },
];

// ============================================================
// SAVE DATA
// ============================================================
interface Save {
  totalGames: number; totalWins: number; totalCaptures: number;
  maxChainJump: number; flawlessWins: number; cleanSweeps: number;
  easyWins: number; medWins: number; hardWins: number;
  fastestWin: number; comebackWins: number; bestStreak: number;
  currentStreak: number; totalKings: number; kingCaptures: number;
  noKingWins: number; perfectGames: number; timedWins: number;
  modesPlayed: Set<string>;
  achUnlocked: Set<string>;
  selectedTheme: number; selectedSkin: number;
  sfxOn: boolean; musicOn: boolean;
  highScores: { mode: string; time: number; captures: number; date: string }[];
}

function defaultSave(): Save {
  return {
    totalGames:0, totalWins:0, totalCaptures:0,
    maxChainJump:0, flawlessWins:0, cleanSweeps:0,
    easyWins:0, medWins:0, hardWins:0,
    fastestWin:Infinity, comebackWins:0, bestStreak:0,
    currentStreak:0, totalKings:0, kingCaptures:0,
    noKingWins:0, perfectGames:0, timedWins:0,
    modesPlayed: new Set(), achUnlocked: new Set(),
    selectedTheme:0, selectedSkin:0,
    sfxOn:true, musicOn:true,
    highScores:[],
  };
}

function loadSave(): Save {
  try {
    const raw = localStorage.getItem('neon-checkers-save');
    if (!raw) return defaultSave();
    const j = JSON.parse(raw);
    j.modesPlayed = new Set(j.modesPlayed || []);
    j.achUnlocked = new Set(j.achUnlocked || []);
    if (j.fastestWin === null || j.fastestWin === undefined) j.fastestWin = Infinity;
    return j;
  } catch { return defaultSave(); }
}

function writeSave(s: Save) {
  const j: any = { ...s, modesPlayed: [...s.modesPlayed], achUnlocked: [...s.achUnlocked] };
  localStorage.setItem('neon-checkers-save', JSON.stringify(j));
}

// ============================================================
// AUDIO
// ============================================================
let audioCtx: AudioContext | null = null;
function ensureAudio() { if (!audioCtx) audioCtx = new AudioContext(); return audioCtx; }
function playTone(freq: number, dur: number, vol = 0.15, type: OscillatorType = 'sine') {
  try {
    const ctx = ensureAudio();
    const o = ctx.createOscillator(); const g = ctx.createGain();
    o.type = type; o.frequency.value = freq;
    g.gain.setValueAtTime(vol, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + dur);
    o.connect(g); g.connect(ctx.destination);
    o.start(); o.stop(ctx.currentTime + dur);
  } catch {}
}
function sfxMove() { playTone(440, 0.1, 0.1, 'triangle'); }
function sfxCapture() { playTone(660, 0.15, 0.15, 'square'); playTone(880, 0.15, 0.12, 'sine'); }
function sfxKing() { playTone(523, 0.2, 0.15, 'sine'); playTone(659, 0.2, 0.12, 'sine'); playTone(784, 0.2, 0.1, 'sine'); }
function sfxWin() { playTone(523, 0.15, 0.15); playTone(659, 0.15, 0.12); playTone(784, 0.15, 0.1); playTone(1047, 0.3, 0.15); }
function sfxLose() { playTone(392, 0.2, 0.12); playTone(330, 0.2, 0.1); playTone(262, 0.3, 0.12); }
function sfxClick() { playTone(800, 0.05, 0.08, 'triangle'); }
function sfxSelect() { playTone(600, 0.08, 0.1, 'triangle'); }

// ============================================================
// GAME STATE
// ============================================================
let save = loadSave();
let screen: Screen = 'title';
let mode: Mode = 'solo';
let difficulty = 1; // 0=easy, 1=med, 2=hard
let board: Cell[][] = [];
let turn: PieceColor = 'red'; // red = player, black = AI
let selected: Pos | null = null;
let validMoves: Move[] = [];
let allMoves: Move[] = [];
let gameStartTime = 0;
let gameDuration = 0;
let playerCaptures = 0;
let aiCaptures = 0;
let playerKingsThisGame = 0;
let piecesLost = 0;
let worstDeficit = 0;
let chainLen = 0;
let timerSec = 300; // 5 min for timed
let timerAcc = 0;
let aiThinking = false;
let lastAchToast = '';
let toastTimer = 0;
let pendingMultiJumpFrom: Pos | null = null;

// 3D objects
let boardGroup: Group;
let pieceMeshes: (Mesh | null)[][] = [];
let highlightMeshes: Mesh[] = [];
let selectedHighlight: Mesh | null = null;
let crownMeshes: (Mesh | null)[][] = [];

// Panel docs
let titleDoc: UIKitDocument | null = null;
let modeDoc: UIKitDocument | null = null;
let diffDoc: UIKitDocument | null = null;
let hudDoc: UIKitDocument | null = null;
let gameoverDoc: UIKitDocument | null = null;
let pauseDoc: UIKitDocument | null = null;
let settingsDoc: UIKitDocument | null = null;
let helpDoc: UIKitDocument | null = null;
let achDoc: UIKitDocument | null = null;
let statsDoc: UIKitDocument | null = null;
let skinsDoc: UIKitDocument | null = null;
let toastDoc: UIKitDocument | null = null;
let countdownDoc: UIKitDocument | null = null;
let leaderDoc: UIKitDocument | null = null;

// World ref
let worldRef: World;

// ============================================================
// BOARD LOGIC
// ============================================================
function initBoard(): Cell[][] {
  const b: Cell[][] = [];
  for (let r = 0; r < BOARD_SIZE; r++) {
    b[r] = [];
    for (let c = 0; c < BOARD_SIZE; c++) {
      if ((r + c) % 2 === 1) {
        if (r < 3) b[r][c] = { piece: 'black', king: false };
        else if (r > 4) b[r][c] = { piece: 'red', king: false };
        else b[r][c] = { piece: null, king: false };
      } else {
        b[r][c] = { piece: null, king: false };
      }
    }
  }
  return b;
}

function getMovesForPiece(b: Cell[][], r: number, c: number): Move[] {
  const cell = b[r][c];
  if (!cell.piece) return [];
  const moves: Move[] = [];
  const dirs: number[] = cell.king ? [-1, 1] : (cell.piece === 'red' ? [-1] : [1]);
  // Simple moves
  for (const dr of dirs) {
    for (const dc of [-1, 1]) {
      const nr = r + dr, nc = c + dc;
      if (nr >= 0 && nr < 8 && nc >= 0 && nc < 8 && !b[nr][nc].piece) {
        moves.push({ from: { r, c }, to: { r: nr, c: nc }, captures: [] });
      }
    }
  }
  // Capture moves
  const captures = getCapturesForPiece(b, r, c, []);
  moves.push(...captures);
  return moves;
}

function getCapturesForPiece(b: Cell[][], r: number, c: number, captured: Pos[]): Move[] {
  const cell = b[r][c];
  if (!cell.piece) return [];
  const dirs: number[] = cell.king ? [-1, 1] : (cell.piece === 'red' ? [-1] : [1]);
  const moves: Move[] = [];
  for (const dr of dirs) {
    for (const dc of [-1, 1]) {
      const mr = r + dr, mc = c + dc;
      const lr = r + dr * 2, lc = c + dc * 2;
      if (lr >= 0 && lr < 8 && lc >= 0 && lc < 8 &&
          b[mr][mc].piece && b[mr][mc].piece !== cell.piece &&
          !b[lr][lc].piece &&
          !captured.some(p => p.r === mr && p.c === mc)) {
        const newCaptures = [...captured, { r: mr, c: mc }];
        // Check for further captures from landing spot
        const tempBoard = cloneBoard(b);
        tempBoard[lr][lc] = { ...tempBoard[r][c] };
        tempBoard[r][c] = { piece: null, king: false };
        tempBoard[mr][mc] = { piece: null, king: false };
        // Temp king promotion for multi-jump
        if ((cell.piece === 'red' && lr === 0) || (cell.piece === 'black' && lr === 7)) {
          tempBoard[lr][lc].king = true;
        }
        const further = getCapturesForPiece(tempBoard, lr, lc, newCaptures);
        if (further.length > 0) {
          for (const f of further) {
            moves.push({ from: { r, c }, to: f.to, captures: [...newCaptures, ...f.captures.filter(fc => !newCaptures.some(nc => nc.r === fc.r && nc.c === fc.c))] });
          }
        } else {
          moves.push({ from: { r, c }, to: { r: lr, c: lc }, captures: newCaptures });
        }
      }
    }
  }
  return moves;
}

function getAllMoves(b: Cell[][], color: PieceColor): Move[] {
  const moves: Move[] = [];
  for (let r = 0; r < 8; r++) {
    for (let c = 0; c < 8; c++) {
      if (b[r][c].piece === color) {
        moves.push(...getMovesForPiece(b, r, c));
      }
    }
  }
  // Mandatory capture: if any capture exists, filter to captures only
  const captures = moves.filter(m => m.captures.length > 0);
  if (captures.length > 0) return captures;
  return moves;
}

function cloneBoard(b: Cell[][]): Cell[][] {
  return b.map(row => row.map(cell => ({ ...cell })));
}

function executeMove(b: Cell[][], m: Move): Cell[][] {
  const nb = cloneBoard(b);
  nb[m.to.r][m.to.c] = { ...nb[m.from.r][m.from.c] };
  nb[m.from.r][m.from.c] = { piece: null, king: false };
  for (const cap of m.captures) {
    nb[cap.r][cap.c] = { piece: null, king: false };
  }
  // King promotion
  const piece = nb[m.to.r][m.to.c];
  if (piece.piece === 'red' && m.to.r === 0) piece.king = true;
  if (piece.piece === 'black' && m.to.r === 7) piece.king = true;
  return nb;
}

function countPieces(b: Cell[][], color: PieceColor): number {
  let n = 0;
  for (let r = 0; r < 8; r++) for (let c = 0; c < 8; c++) if (b[r][c].piece === color) n++;
  return n;
}

function checkWinner(b: Cell[][]): PieceColor | 'draw' | null {
  const redCount = countPieces(b, 'red');
  const blackCount = countPieces(b, 'black');
  if (redCount === 0) return 'black';
  if (blackCount === 0) return 'red';
  const redMoves = getAllMoves(b, 'red');
  const blackMoves = getAllMoves(b, 'black');
  if (redMoves.length === 0 && turn === 'red') return 'black';
  if (blackMoves.length === 0 && turn === 'black') return 'red';
  return null;
}

// ============================================================
// AI
// ============================================================
function evaluateBoard(b: Cell[][], color: PieceColor): number {
  let score = 0;
  for (let r = 0; r < 8; r++) {
    for (let c = 0; c < 8; c++) {
      const cell = b[r][c];
      if (!cell.piece) continue;
      const val = cell.king ? 3 : 1;
      // Positional bonus: center control, advancement
      let posBonus = 0;
      if (c >= 2 && c <= 5) posBonus += 0.1;
      if (cell.piece === 'red') posBonus += (7 - r) * 0.05;
      else posBonus += r * 0.05;
      // Back row defense
      if (cell.piece === 'red' && r === 7 && !cell.king) posBonus += 0.2;
      if (cell.piece === 'black' && r === 0 && !cell.king) posBonus += 0.2;

      if (cell.piece === color) score += val + posBonus;
      else score -= val + posBonus;
    }
  }
  return score;
}

function minimax(b: Cell[][], depth: number, alpha: number, beta: number, maximizing: boolean, aiColor: PieceColor): number {
  const winner = checkWinnerStatic(b);
  if (winner === aiColor) return 100;
  if (winner && winner !== aiColor && winner !== 'draw') return -100;
  if (winner === 'draw') return 0;
  if (depth === 0) return evaluateBoard(b, aiColor);

  const currentColor = maximizing ? aiColor : (aiColor === 'red' ? 'black' : 'red');
  const moves = getAllMovesForEval(b, currentColor);
  if (moves.length === 0) return maximizing ? -100 : 100;

  if (maximizing) {
    let maxEval = -Infinity;
    for (const m of moves) {
      const nb = executeMove(b, m);
      const ev = minimax(nb, depth - 1, alpha, beta, false, aiColor);
      maxEval = Math.max(maxEval, ev);
      alpha = Math.max(alpha, ev);
      if (beta <= alpha) break;
    }
    return maxEval;
  } else {
    let minEval = Infinity;
    for (const m of moves) {
      const nb = executeMove(b, m);
      const ev = minimax(nb, depth - 1, alpha, beta, true, aiColor);
      minEval = Math.min(minEval, ev);
      beta = Math.min(beta, ev);
      if (beta <= alpha) break;
    }
    return minEval;
  }
}

function checkWinnerStatic(b: Cell[][]): PieceColor | 'draw' | null {
  const rc = countPieces(b, 'red');
  const bc = countPieces(b, 'black');
  if (rc === 0) return 'black';
  if (bc === 0) return 'red';
  return null;
}

function getAllMovesForEval(b: Cell[][], color: PieceColor): Move[] {
  const moves: Move[] = [];
  for (let r = 0; r < 8; r++) {
    for (let c = 0; c < 8; c++) {
      if (b[r][c].piece === color) {
        moves.push(...getMovesForPiece(b, r, c));
      }
    }
  }
  const captures = moves.filter(m => m.captures.length > 0);
  if (captures.length > 0) return captures;
  return moves;
}

function aiMove(): Move | null {
  const aiColor: PieceColor = 'black';
  const moves = getAllMoves(board, aiColor);
  if (moves.length === 0) return null;
  const depths = [1, 3, 5]; // easy, medium, hard
  const d = depths[Math.min(difficulty, 2)];
  let bestMove = moves[0];
  let bestScore = -Infinity;
  // Add some randomness for easy
  if (difficulty === 0) {
    return moves[Math.floor(Math.random() * moves.length)];
  }
  for (const m of moves) {
    const nb = executeMove(board, m);
    const score = minimax(nb, d - 1, -Infinity, Infinity, false, aiColor);
    if (score > bestScore || (score === bestScore && Math.random() > 0.5)) {
      bestScore = score;
      bestMove = m;
    }
  }
  return bestMove;
}

// ============================================================
// 3D RENDERING
// ============================================================
function cellToWorld(r: number, c: number): { x: number; z: number } {
  return {
    x: BOARD_OFFSET + c * CELL_SIZE,
    z: BOARD_OFFSET + r * CELL_SIZE,
  };
}

function createBoardVisuals(scene: any) {
  boardGroup = new Group();
  boardGroup.position.set(0, BOARD_Y, -0.5);
  scene.add(boardGroup);

  const theme = THEMES[save.selectedTheme];

  // Board base
  const baseGeo = new BoxGeometry(BOARD_SIZE * CELL_SIZE + 0.04, 0.02, BOARD_SIZE * CELL_SIZE + 0.04);
  const baseMat = new MeshStandardMaterial({ color: new Color(theme.gridC), metalness: 0.5, roughness: 0.3 });
  const baseMesh = new Mesh(baseGeo, baseMat);
  baseMesh.position.set(0, -0.01, 0);
  boardGroup.add(baseMesh);

  // Board squares
  for (let r = 0; r < 8; r++) {
    for (let c = 0; c < 8; c++) {
      const isDark = (r + c) % 2 === 1;
      const geo = new BoxGeometry(CELL_SIZE - 0.002, 0.005, CELL_SIZE - 0.002);
      const mat = new MeshStandardMaterial({
        color: new Color(isDark ? theme.dark : theme.light),
        metalness: 0.3,
        roughness: 0.5,
        emissive: new Color(isDark ? theme.dark : theme.light),
        emissiveIntensity: 0.15,
      });
      const mesh = new Mesh(geo, mat);
      const pos = cellToWorld(r, c);
      mesh.position.set(pos.x, 0.005, pos.z);
      mesh.userData = { boardCell: true, row: r, col: c };
      boardGroup.add(mesh);
    }
  }

  // Coordinate labels (A-H, 1-8)
  // (skip text labels — use edge markers instead)
  const edgeGeo = new BoxGeometry(CELL_SIZE * 8 + 0.01, 0.003, 0.005);
  const edgeMat = new MeshStandardMaterial({ color: new Color(theme.accent), emissive: new Color(theme.accent), emissiveIntensity: 0.5 });
  for (const z of [-1, 1]) {
    const edge = new Mesh(edgeGeo, edgeMat);
    edge.position.set(0, 0.008, z * (CELL_SIZE * 4 + 0.005));
    boardGroup.add(edge);
  }
  const edgeGeo2 = new BoxGeometry(0.005, 0.003, CELL_SIZE * 8 + 0.01);
  for (const x of [-1, 1]) {
    const edge = new Mesh(edgeGeo2, edgeMat);
    edge.position.set(x * (CELL_SIZE * 4 + 0.005), 0.008, 0);
    boardGroup.add(edge);
  }

  // Init piece meshes grid
  pieceMeshes = [];
  crownMeshes = [];
  for (let r = 0; r < 8; r++) {
    pieceMeshes[r] = [];
    crownMeshes[r] = [];
    for (let c = 0; c < 8; c++) {
      pieceMeshes[r][c] = null;
      crownMeshes[r][c] = null;
    }
  }
}

function getSkinColors(color: PieceColor): { body: string; edge: string } {
  const skin = SKINS[save.selectedSkin];
  return color === 'red'
    ? { body: skin.redBody, edge: skin.redEdge }
    : { body: skin.blackBody, edge: skin.blackEdge };
}

function createPieceMesh(color: PieceColor, king: boolean): Mesh {
  const skinC = getSkinColors(color);
  const geo = new CylinderGeometry(PIECE_RADIUS, PIECE_RADIUS, PIECE_HEIGHT, 24);
  const mat = new MeshStandardMaterial({
    color: new Color(skinC.body),
    metalness: 0.6,
    roughness: 0.2,
    emissive: new Color(skinC.edge),
    emissiveIntensity: 0.3,
  });
  const mesh = new Mesh(geo, mat);
  return mesh;
}

function createCrownMesh(): Mesh {
  const geo = new TorusGeometry(PIECE_RADIUS * 0.6, 0.003, 8, 16);
  const mat = new MeshStandardMaterial({
    color: new Color('#ffcc00'),
    emissive: new Color('#ffcc00'),
    emissiveIntensity: 0.8,
    metalness: 0.8,
    roughness: 0.1,
  });
  const mesh = new Mesh(geo, mat);
  mesh.rotation.x = Math.PI / 2;
  return mesh;
}

function syncBoardVisuals() {
  for (let r = 0; r < 8; r++) {
    for (let c = 0; c < 8; c++) {
      const cell = board[r][c];
      const existing = pieceMeshes[r][c];
      const existingCrown = crownMeshes[r][c];
      const pos = cellToWorld(r, c);

      if (cell.piece) {
        if (!existing) {
          const mesh = createPieceMesh(cell.piece, cell.king);
          mesh.position.set(pos.x, PIECE_HEIGHT / 2 + 0.008, pos.z);
          mesh.userData = { isPiece: true, row: r, col: c };
          boardGroup.add(mesh);
          pieceMeshes[r][c] = mesh;
        } else {
          // Update position and color
          existing.position.set(pos.x, PIECE_HEIGHT / 2 + 0.008, pos.z);
          const skinC = getSkinColors(cell.piece);
          (existing.material as MeshStandardMaterial).color.set(skinC.body);
          (existing.material as MeshStandardMaterial).emissive.set(skinC.edge);
          existing.userData.row = r;
          existing.userData.col = c;
        }

        // Crown
        if (cell.king) {
          if (!existingCrown) {
            const crown = createCrownMesh();
            crown.position.set(pos.x, PIECE_HEIGHT + 0.012, pos.z);
            boardGroup.add(crown);
            crownMeshes[r][c] = crown;
          } else {
            existingCrown.position.set(pos.x, PIECE_HEIGHT + 0.012, pos.z);
          }
        } else if (existingCrown) {
          boardGroup.remove(existingCrown);
          crownMeshes[r][c] = null;
        }
      } else {
        if (existing) {
          boardGroup.remove(existing);
          pieceMeshes[r][c] = null;
        }
        if (existingCrown) {
          boardGroup.remove(existingCrown);
          crownMeshes[r][c] = null;
        }
      }
    }
  }
}

function clearHighlights() {
  for (const h of highlightMeshes) boardGroup.remove(h);
  highlightMeshes = [];
  if (selectedHighlight) {
    boardGroup.remove(selectedHighlight);
    selectedHighlight = null;
  }
}

function showHighlights() {
  clearHighlights();
  const theme = THEMES[save.selectedTheme];
  // Highlight selected piece
  if (selected) {
    const pos = cellToWorld(selected.r, selected.c);
    const geo = new RingGeometry(PIECE_RADIUS - 0.005, PIECE_RADIUS + 0.005, 24);
    const mat = new MeshBasicMaterial({ color: new Color('#ffff00'), side: DoubleSide });
    const mesh = new Mesh(geo, mat);
    mesh.position.set(pos.x, 0.012, pos.z);
    mesh.rotation.x = -Math.PI / 2;
    boardGroup.add(mesh);
    selectedHighlight = mesh;
  }
  // Highlight valid destinations
  for (const m of validMoves) {
    const pos = cellToWorld(m.to.r, m.to.c);
    const isCapture = m.captures.length > 0;
    const geo = new BoxGeometry(CELL_SIZE - 0.01, 0.003, CELL_SIZE - 0.01);
    const mat = new MeshBasicMaterial({
      color: new Color(isCapture ? '#ff4444' : theme.accent),
      transparent: true,
      opacity: 0.5,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.set(pos.x, 0.01, pos.z);
    mesh.userData = { isHighlight: true, moveIdx: validMoves.indexOf(m) };
    boardGroup.add(mesh);
    highlightMeshes.push(mesh);
  }
}

// ============================================================
// ENVIRONMENT
// ============================================================
function createEnvironment(scene: any) {
  const theme = THEMES[save.selectedTheme];
  scene.background = new Color(theme.bg);
  scene.fog = new FogExp2(new Color(theme.fog), 0.3);

  // Lights
  const ambient = new AmbientLight(new Color('#ffffff'), 0.3);
  scene.add(ambient);
  const dir = new DirectionalLight(new Color('#ffffff'), 0.6);
  dir.position.set(2, 4, 2);
  scene.add(dir);
  const accent1 = new PointLight(new Color(theme.accent), 1, 5);
  accent1.position.set(-1, 2, -1);
  scene.add(accent1);
  const accent2 = new PointLight(new Color(theme.accent), 0.5, 5);
  accent2.position.set(1, 2, 1);
  scene.add(accent2);

  // Holodeck grid floor
  const gridGroup = new Group();
  const gridMat = new LineBasicMaterial({ color: new Color(theme.gridC), transparent: true, opacity: 0.3 });
  const gridSize = 20;
  const gridStep = 0.5;
  for (let i = -gridSize; i <= gridSize; i += gridStep) {
    const pts1 = new Float32Array([i, 0, -gridSize, i, 0, gridSize]);
    const bg1 = new BufferGeometry(); bg1.setAttribute('position', new Float32BufferAttribute(pts1, 3));
    gridGroup.add(new LineSegments(bg1, gridMat));
    const pts2 = new Float32Array([-gridSize, 0, i, gridSize, 0, i]);
    const bg2 = new BufferGeometry(); bg2.setAttribute('position', new Float32BufferAttribute(pts2, 3));
    gridGroup.add(new LineSegments(bg2, gridMat));
  }
  scene.add(gridGroup);

  // Corner pillars
  const pillarGeo = new CylinderGeometry(0.03, 0.03, 2, 8);
  const pillarMat = new MeshStandardMaterial({ color: new Color(theme.accent), emissive: new Color(theme.accent), emissiveIntensity: 0.5, metalness: 0.8, roughness: 0.2 });
  const bSize = BOARD_SIZE * CELL_SIZE / 2 + 0.08;
  for (const [x, z] of [[-bSize, -bSize], [bSize, -bSize], [-bSize, bSize], [bSize, bSize]]) {
    const pillar = new Mesh(pillarGeo, pillarMat);
    pillar.position.set(x, BOARD_Y + 0.5, z - 0.5);
    scene.add(pillar);
  }
}

