function showScreen(s: Screen) {
  screen = s;
  const docs: [UIKitDocument | null, Screen[]][] = [
    [titleDoc, ['title']],
    [modeDoc, ['modeselect']],
    [diffDoc, ['difficulty']],
    [hudDoc, ['playing']],
    [gameoverDoc, ['gameover']],
    [pauseDoc, ['paused']],
    [settingsDoc, ['settings']],
    [helpDoc, ['help']],
    [achDoc, ['achievements']],
    [statsDoc, ['stats']],
    [skinsDoc, ['skins']],
    [countdownDoc, ['countdown']],
    [leaderDoc, ['leaderboard']],
  ];
  for (const [doc, screens] of docs) {
    if (!doc) continue;
    const panel = doc.getParent();
    if (panel) {
      const show = screens.includes(s);
      panel.visible = show;
    }
  }
}

