function updateHud() {
  if (!hudDoc) return;
  const elapsed = screen === 'playing' ? (Date.now() - gameStartTime) / 1000 : gameDuration;
  const mins = Math.floor(elapsed / 60);
  const secs = Math.floor(elapsed % 60);
  const timeStr = `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  const redCount = countPieces(board, 'red');
  const blackCount = countPieces(board, 'black');
  const turnStr = turn === 'red' ? 'YOUR TURN' : (aiThinking ? 'AI THINKING...' : 'AI TURN');
  const diffNames = ['Easy', 'Medium', 'Hard'];

  const setText = (name: string, text: string) => {
    const el = hudDoc!.getElementByName(name);
    if (el) el.setProperties({ text });
  };
  setText('turn-display', turnStr);
  setText('time-display', timeStr);
  setText('player-count', `You: ${redCount}`);
  setText('ai-count', `AI: ${blackCount}`);
  setText('diff-display', diffNames[difficulty]);
  setText('mode-display', mode.toUpperCase());

  if (mode === 'timed' || mode === 'blitz') {
    const tMins = Math.floor(timerSec / 60);
    const tSecs = Math.floor(timerSec % 60);
    setText('timer-display', `${tMins}:${tSecs < 10 ? '0' : ''}${tSecs}`);
  }
}

function updateSettings() {
  if (!settingsDoc) return;
  const setText = (name: string, text: string) => {
    const el = settingsDoc!.getElementByName(name);
    if (el) el.setProperties({ text });
  };
  setText('sfx-status', save.sfxOn ? 'ON' : 'OFF');
  setText('music-status', save.musicOn ? 'ON' : 'OFF');
  setText('theme-name', THEMES[save.selectedTheme].name);
}

function updateAchievements() {
  if (!achDoc) return;
  // Check new achievements
  checkAchievements();
  for (let i = 0; i < ACHS.length; i++) {
    const el = achDoc.getElementByName(`ach-${i}`);
    if (!el) continue;
    const unlocked = save.achUnlocked.has(ACHS[i].id);
    el.setProperties({ text: `${unlocked ? '[*]' : '[ ]'} ${ACHS[i].name} - ${ACHS[i].desc}` });
  }
  const countEl = achDoc.getElementByName('ach-count');
  if (countEl) countEl.setProperties({ text: `${save.achUnlocked.size}/${ACHS.length} Unlocked` });
}

function updateStats() {
  if (!statsDoc) return;
  const setText = (name: string, text: string) => {
    const el = statsDoc!.getElementByName(name);
    if (el) el.setProperties({ text });
  };
  setText('stat-games', `Games Played: ${save.totalGames}`);
  setText('stat-wins', `Wins: ${save.totalWins}`);
  setText('stat-captures', `Total Captures: ${save.totalCaptures}`);
  setText('stat-kings', `Kings Crowned: ${save.totalKings || 0}`);
  setText('stat-streak', `Best Streak: ${save.bestStreak}`);
  setText('stat-chain', `Best Chain Jump: ${save.maxChainJump}`);
  setText('stat-fastest', `Fastest Win: ${save.fastestWin === Infinity ? '--' : Math.floor(save.fastestWin) + 's'}`);
  setText('stat-flawless', `Flawless Wins: ${save.flawlessWins}`);
  setText('stat-modes', `Modes Played: ${save.modesPlayed?.size || 0}`);
}

function updateSkins() {
  if (!skinsDoc) return;
  for (let i = 0; i < SKINS.length; i++) {
    const el = skinsDoc.getElementByName(`btn-skin-${i}`);
    if (!el) continue;
    const unlocked = SKINS[i].req(save);
    const selected = save.selectedSkin === i;
    const label = unlocked
      ? `${selected ? '>> ' : ''}${SKINS[i].name}${selected ? ' <<' : ''}`
      : `[LOCKED] ${SKINS[i].unlock}`;
    el.setProperties({ text: label });
  }
}

function updateLeaderboard() {
  if (!leaderDoc) return;
  const scores = save.highScores.slice(0, 10);
  for (let i = 0; i < 10; i++) {
    const el = leaderDoc.getElementByName(`score-${i}`);
    if (!el) continue;
    if (i < scores.length) {
      const s = scores[i];
      el.setProperties({ text: `#${i + 1} ${s.mode} - ${s.captures} caps - ${Math.floor(s.time)}s` });
    } else {
      el.setProperties({ text: `#${i + 1} ---` });
    }
  }
}

function updateGameover(winner: PieceColor | 'draw') {
  if (!gameoverDoc) return;
  const setText = (name: string, text: string) => {
    const el = gameoverDoc!.getElementByName(name);
    if (el) el.setProperties({ text });
  };
  if (winner === 'draw') {
    setText('result-text', 'DRAW');
    setText('result-detail', 'Neither side could win');
  } else if (winner === 'red') {
    setText('result-text', 'YOU WIN!');
    setText('result-detail', `Captured ${playerCaptures} pieces in ${Math.floor(gameDuration)}s`);
  } else {
    setText('result-text', 'AI WINS');
    setText('result-detail', `AI captured ${aiCaptures} of your pieces`);
  }
}

function showToast(msg: string) {
  if (!toastDoc) return;
  const el = toastDoc.getElementByName('toast-text');
  if (el) el.setProperties({ text: msg });
  const panel = toastDoc.getParent();
  if (panel) panel.visible = true;
  toastTimer = 3;
}

function checkAchievements() {
