function endGame(winner: PieceColor | 'draw') {
  gameDuration = (Date.now() - gameStartTime) / 1000;
  save.totalGames++;
  save.modesPlayed.add(mode);
  save.totalCaptures += playerCaptures;
  save.totalKings = (save.totalKings || 0) + playerKingsThisGame;

  if (winner === 'red') {
