    save.bestStreak = Math.max(save.bestStreak, save.currentStreak);
    if (gameDuration < save.fastestWin) save.fastestWin = gameDuration;
    if (piecesLost === 0) save.flawlessWins++;
    if (countPieces(board, 'black') === 0) save.cleanSweeps++;
    if (piecesLost === 0 && countPieces(board, 'black') === 0) save.perfectGames = (save.perfectGames || 0) + 1;
    if (worstDeficit >= 3) save.comebackWins = (save.comebackWins || 0) + 1;
    if (playerKingsThisGame === 0) save.noKingWins = (save.noKingWins || 0) + 1;
    if (difficulty === 0) save.easyWins++;
    if (difficulty === 1) save.medWins++;
    if (difficulty === 2) save.hardWins++;
    if (mode === 'timed' || mode === 'blitz') save.timedWins = (save.timedWins || 0) + 1;
