function handleCellClick(r: number, c: number) {
  if (screen !== 'playing' || turn !== 'red' || aiThinking) return;

  const cell = board[r][c];

  // If we have a pending multi-jump, only allow clicking the destination
  if (pendingMultiJumpFrom) {
    // Check if this click is a valid continuation
    const contMoves = validMoves.filter(m => m.to.r === r && m.to.c === c);
    if (contMoves.length > 0) {
      applyPlayerMove(contMoves[0]);
    }
    return;
  }

  // Clicked own piece — select it
  if (cell.piece === 'red') {
    const pieceMoves = allMoves.filter(m => m.from.r === r && m.from.c === c);
    if (pieceMoves.length > 0) {
      selected = { r, c };
      validMoves = pieceMoves;
      sfxSelect();
      showHighlights();
    }
    return;
  }

  // Clicked destination
  if (selected) {
    const move = validMoves.find(m => m.to.r === r && m.to.c === c);
    if (move) {
