function initBoard(): Cell[][] {
  const b: Cell[][] = [];
  for (let r=0; r<8; r++) { b[r]=[]; for (let c=0; c<8; c++) {
    if ((r+c)%2===1) {
      if (r<3) b[r][c]={piece:'black',king:false};
      else if (r>4) b[r][c]={piece:'red',king:false};
