    const further=getCapturesForPiece(tb,lr,lc,nc);
    if (further.length>0) for (const f of further) {
      const allCaps=[...nc,...f.captures.filter(fc=>!nc.some(n2=>n2.r===fc.r&&n2.c===fc.c))];
      moves.push({from:{r,c},to:f.to,captures:allCaps});
